$content = "`n`n// HarmonyOS & Mobile Keyboard Fix`n(function() {`n    if (window.visualViewport) {`n        window.visualViewport.addEventListener('resize', function() {`n            document.body.style.height = window.visualViewport.height + 'px';`n            window.scrollTo(0, 0);`n        });`n    }`n    `n    // Focus scrollIntoView for inputs`n    document.addEventListener('focusin', function(e) {`n        if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') {`n            setTimeout(function() {`n                e.target.scrollIntoView({ behavior: 'smooth', block: 'end' });`n            }, 300);`n        }`n    });`n})();"
Add-Content -Path "js\main.js" -Value $content